def ev(source_title, quote="根据企业公开信息"):
    return [{"source_title": source_title, "source_url": None, "quote": quote}]

def write_batch(batch_num, nodes, edges, companies, exposures):
    graph = {"batch_id": f"batch_{batch_num}_nodes", "task_description": f"Batch {batch_num} industrial nodes and edges", "nodes_to_upsert": nodes, "edges_to_upsert": edges}
    with open(os.path.join(BASE_DIR, "tmp_script", f"batch_{batch_num}_nodes.json"), "w", encoding="utf-8") as f:
        json.dump(graph, f, ensure_ascii=False, indent=2)
    business = {"batch_id": f"batch_{batch_num}_business", "task_description": f"Batch {batch_num} business registration", "companies_to_upsert": companies, "company_node_exposures_to_upsert": exposures, "industries_to_upsert": [], "industry_node_mappings_to_upsert": []}
    with open(os.path.join(BASE_DIR, "tmp_script", f"batch_{batch_num}_business.json"), "w", encoding="utf-8") as f:
        json.dump(business, f, ensure_ascii=False, indent=2)
    print(f"Batch {batch_num}: {len(nodes)} nodes, {len(edges)} edges, {len(companies)} companies, {len(exposures)} exposures")

